using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;


    // Get active design
    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get root component in this design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Get fillet features
    Ptr features = rootComp->features();
    if (!features)
        return false;

    Ptr fillets = features->filletFeatures();
    if (!fillets)
        return false;

    // Get edges of top face in the first body
    Ptr bodies = rootComp->bRepBodies();
    if (!bodies)
        return false;

    Ptr body1 = bodies->item(0);
    if (!body1)
        return false;

    Ptr faces1 = body1->faces();
    if (!faces1)
        return false;

    Ptr face1 = faces1->item(0);
    if (!face1)
        return false;

    Ptr edges1 = face1->edges();
    if (!edges1)
        return false;

    // Create constant-radius fillet
    Ptr edgeCollection1 = ObjectCollection::create();
    if (!edgeCollection1)
        return false;

    for (Ptr edge : edges1)
        edgeCollection1->add(edge);

    Ptr radius1 = ValueInput::createByReal(0.3);
    if (!radius1)
        return false;

    Ptr input1 = fillets->createInput();
    if (!input1)
        return false;

    input1->isRollingBallCorner(true);

    Ptr edgeSets1 = input1->edgeSetInputs();
    if (!edgeSets1)
        return false;

    Ptr constRadiusInput =
        edgeSets1->addConstantRadiusEdgeSet(edgeCollection1, radius1, true);
    if (!constRadiusInput)
        return false;

    constRadiusInput->continuity(adsk::fusion::SurfaceContinuityTypes::TangentSurfaceContinuityType);

    Ptr fillet1 = fillets->add(input1);
    if (!fillet1)
        return false;

    fillet1->deleteMe();

    // Create variable-radius fillet
    Ptr edgeCollection2 = ObjectCollection::create();
    if (!edgeCollection2)
        return false;

    Ptr edge1 = edges1->item(0);
    if (!edge1)
        return false;
    edgeCollection2->add(edge1);

    Ptr startRadius = ValueInput::createByString("1.0 mm");
    if (!startRadius)
        return false;

    Ptr endRadius = ValueInput::createByString("5.0 mm");
    if (!endRadius)
        return false;

    Ptr input2 = fillets->createInput();
    if (!input2)
        return false;

    input2->isRollingBallCorner(false);

    Ptr edgeSets2 = input2->edgeSetInputs();
    if (!edgeSets2)
        return false;

    Ptr varRadiusEdgeSetInput =
        edgeSets2->addVariableRadiusEdgeSet(edgeCollection2, startRadius, endRadius, false);

    std::vector> radii;
    radii.push_back(ValueInput::createByString("2.0 mm"));
    radii.push_back(ValueInput::createByString("3.0 mm"));
    std::vector> positions;
    positions.push_back(ValueInput::createByReal(0.3));
    positions.push_back(ValueInput::createByReal(0.6));
    varRadiusEdgeSetInput->setMidRadii(radii, positions);

    Ptr fillet2 = fillets->add(input2);
    if (!fillet2)
        return false;

    fillet2->deleteMe();

    // Create chord-length fillet
    Ptr input3 = fillets->createInput();
    if (!input3)
        return false;

    input3->isRollingBallCorner(true);

    Ptr edgeSets3 = input3->edgeSetInputs();
    if (!edgeSets3)
        return false;

    Ptr chordLength = ValueInput::createByReal(1.0);
    if (!chordLength)
        return false;

    Ptr chordLengthInputSet =
        edgeSets3->addChordLengthEdgeSet(edgeCollection1, chordLength, true);
    if (!chordLengthInputSet)
        return false;

    chordLengthInputSet->continuity(adsk::fusion::SurfaceContinuityTypes::TangentSurfaceContinuityType);
    Ptr fillet3 = fillets->add(input3);
    if (!fillet3)
        return false;


    return true;
}
